class Solution:
    def distinctNames(self, ideas):
        groups = [set() for _ in range(26)]
        for w in ideas:
            groups[ord(w[0]) - 97].add(w[1:])
        total = 0
        for i in range(26):
            if not groups[i]:
                continue
            for j in range(i + 1, 26):
                if not groups[j]:
                    continue
                shared = len(groups[i] & groups[j])
                total += 2 * (len(groups[i]) - shared) * (len(groups[j]) - shared)
        return total

