var distinctNames = function(ideas) {
    const groups = Array.from({length: 26}, () => new Set());
    for (const w of ideas) {
        groups[w.charCodeAt(0) - 97].add(w.slice(1));
    }
    let total = 0;
    for (let i = 0; i < 26; i++) {
        if (groups[i].size === 0) continue;
        for (let j = i + 1; j < 26; j++) {
            if (groups[j].size === 0) continue;
            let shared = 0;
            const [small, large] = groups[i].size < groups[j].size ? [groups[i], groups[j]] : [groups[j], groups[i]];
            for (const s of small) if (large.has(s)) shared++;
            total += 2 * (groups[i].size - shared) * (groups[j].size - shared);
        }
    }
    return total;
};
